suspend fun awaitCallback(): String = suspendCoroutine { cont ->
    someApi.doSomething(object : Callback {
        override fun onSuccess(result: String) = cont.resume(result)
        override fun onError(e: Exception) = cont.resumeWithException(e)
    })
}

suspend fun awaitCallback(): String = suspendCancellableCoroutine { cont ->
    val call = someApi.doSomething(object : Callback {
        override fun onSuccess(result: String) = cont.resume(result)
        override fun onError(e: Exception) = cont.resumeWithException(e)
    })
    cont.invokeOnCancellation { call.cancel() } // Clean up on cancel
}

