class DatabaseManager private constructor(val url: String) {

    companion object {
        @Volatile
        private var instance: DatabaseManager? = null

        fun getInstance(url: String): DatabaseManager {
            return instance ?: synchronized(this) {
                instance ?: DatabaseManager(url).also { instance = it }
            }
        }
    }
}

